  ('real-estate-moex-00444', 'real-estate', 'real-estate-moex-110-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '100坪之辦公室出租，每月每坪正常租金為1,000元，推估該辦公室合理空置率為8%，每年之地 價稅、房屋稅、保險費、管理費及維修費為120,000元，貸款支出為200,000元。該辦公室每年之 淨收益為多少？', '["1,080,000元", "984,000元", "880,000元", "784,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "cf2e8767ac8b", "answer_pdf_sha1": "159aeb8aff30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
